import { useEffect, useState } from "react";
import API_BASE_URL from "../api"; // Import backend URL

function Profile() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch user's capsules from the backend
    fetch(`${API_BASE_URL}/api/user/capsules`)
      .then((response) => response.json())
      .then((data) => {
        setCapsules(data);
        setLoading(false);
      })
      .catch((error) => {
        console.error("Error fetching user capsules:", error);
        setLoading(false);
      });
  }, []);

  return (
    <div>
      <h1>Your Profile</h1>
      <p>Manage your time capsules here.</p>

      <h2>Your Capsules</h2>
      {loading ? (
        <p>Loading...</p>
      ) : capsules.length > 0 ? (
        <ul>
          {capsules.map((capsule) => (
            <li key={capsule.id}>
              <h3>{capsule.title}</h3>
              <p>{capsule.description}</p>
            </li>
          ))}
        </ul>
      ) : (
        <p>You haven't created any capsules yet.</p>
      )}
    </div>
  );
}

export default Profile;
